type Config struct {
	XMLName  xml.Name  `xml:"config"`
	Settings []Setting `xml:"settings>setting"`
	Database Database  `xml:"database"`
	Server   Server    `xml:"server"`
}

type Setting struct {
	Name  string `xml:"name,attr"`
	Value string `xml:"value,attr"`
}

type Database struct {
	Host     string `xml:"host"`
	Port     int    `xml:"port"`
	Username string `xml:"username"`
	Database string `xml:"database"`
}

type Server struct {
	Host string `xml:"host"`
	Port int    `xml:"port"`
}

const (
	maxXMLSize = 10 * 1024 * 1024 // 10MB limit
)

func ParseXMLConfig(r io.Reader) (*Config, error) {
	limitedReader := io.LimitReader(r, maxXMLSize)
	
	data, err := io.ReadAll(limitedReader)
	if err != nil {
		return nil, fmt.Errorf("failed to read XML data: %w", err)
	}

	if len(data) >= maxXMLSize {
		return nil, errors.New("XML file exceeds maximum allowed size")
	}

	if containsEntityDeclarations(data) {
		return nil, errors.New("XML entity declarations are not allowed for security reasons")
	}

	if containsDoctypeDeclaration(data) {
		return nil, errors.New("DOCTYPE declarations are not allowed for security reasons")
	}

	decoder := xml.NewDecoder(strings.NewReader(string(data)))
	decoder.Strict = true
	decoder.Entity = xml.HTMLEntity

	var config Config
	if err := decoder.Decode(&config); err != nil {
		return nil, fmt.Errorf("failed to parse XML: %w", err)
	}

	if err := validateConfig(&config); err != nil {
		return nil, fmt.Errorf("invalid configuration: %w", err)
	}

	return &config, nil
}

func containsEntityDeclarations(data []byte) bool {
	content := string(data)
	return strings.Contains(content, "<!ENTITY")
}

func containsDoctypeDeclaration(data []byte) bool {
	content := string(data)
	return strings.Contains(content, "<!DOCTYPE")
}

func validateConfig(config *Config) error {
	if config == nil {
		return errors.New("config is nil")
	}

	if config.Database.Host == "" {
		return errors.New("database host is required")
	}

	if config.Database.Port <= 0 || config.Database.Port > 65535 {
		return errors.New("database port must be between 1 and 65535")
	}

	if config.Server.Host == "" {
		return errors.New("server host is required")
	}

	if config.Server.Port <= 0 || config.Server.Port > 65535 {
		return errors.New("server port must be between 1 and 65535")
	}

	for _, setting := range config.Settings {
		if setting.Name == "" {
			return errors.New("setting name cannot be empty")
		}
	}

	return nil
}